                </thead>
                <tbody>
                  {visibleFiles.map((f) => (
                    <tr key={f.id} className="border-t border-border hover:bg-muted/30">
                      <td className="px-3 py-1.5 font-mono max-w-[260px] truncate" title={f.relative_path ?? ""}>
                        {f.relative_path?.split("/").pop() ?? "—"}
